// Call the claimRequest API if this client should capture the request.
//require('claimRequest')();

// Import modules
const log = require('logToConsole');

// Request
const claimRequest = require('claimRequest');
const getRequestPath = require('getRequestPath');
const getRequestMethod = require('getRequestMethod');
const getRequestBody = require('getRequestBody');
const getRequestHeader = require('getRequestHeader'); // Not sure if this is needed

// Response
const sendHttpRequest = require('sendHttpRequest');
const setResponseBody = require('setResponseBody');
const setResponseHeader = require('setResponseHeader');
const setResponseStatus = require('setResponseStatus');
const returnResponse = require('returnResponse');

// Set global variables
const origin = getRequestHeader('origin'); // Unsure if this is needed
const requestPath = getRequestPath();
const requestMethod = getRequestMethod();
const endpoint = [
  'https://graph.facebook.com/',
  data.api_version,
  data.pixel_id,
  'events?access_token=' + data.access_token
];

const sendResponse = (statusCode, body, headers) => {
  // Prevent CORS errors...not sure if this is needed
  if (origin) {
    setResponseHeader('Access-Control-Allow-Origin', origin);
    setResponseHeader('Access-Control-Allow-Credentials', 'true');
    setResponseHeader('Access-Control-Allow-Headers', 'Content-Type, SP-Anonymous');
    setResponseHeader('Access-Control-Allow-Methods', 'POST, GET, OPTIONS');
  }

  // Set response code
  setResponseStatus(statusCode || 200);

  // Set response body and headers
  if (body) {
    setResponseBody(body);
  }
  if (headers) {
    for (const key in headers) {
      setResponseHeader(key, headers[key]);
    }
  }

  // Return the response
  returnResponse();
};


// Claim the request
if(requestPath.match("^/facebook") && requestMethod === 'POST') {
  claimRequest();
  log('Facebook CAPI request claimed...');

  const requestBody = getRequestBody();
  sendHttpRequest(
        endpoint.join('/'),
        (statusCode, headers, body) => {
          if (statusCode >= 200 && statusCode < 300) {
            sendResponse(200, body, headers);
          } else {
            log('CAPI request failed: ', body);
            sendResponse(statusCode, body, headers);
          }
        },
        { timeout: 5000 }

  );
}


