const claimRequest = require('claimRequest');
const getRequestHeader = require('getRequestHeader');
const getRequestPath = require('getRequestPath');
const makeNumber = require('makeNumber');
const returnResponse = require('returnResponse');
const setResponseBody = require('setResponseBody');
const setResponseHeader = require('setResponseHeader');
const setResponseStatus = require('setResponseStatus');

// Abort if request is for _set_cookie, as that should not be caught by a Client
if (getRequestPath() === '/_set_cookie') return;

claimRequest();
const origin = getRequestHeader('origin');
const allowedOrigins = data.allowedOrigins || '';
if (allowedOrigins === '*') {
  setResponseHeader('Access-Control-Allow-Origin', origin);
} else {
  allowedOrigins.split(',').forEach(o => {
    if (o.trim() === origin) setResponseHeader('Access-Control-Allow-Origin', o);
  });
}
setResponseHeader('Access-Control-Allow-Credentials', 'true');
if (data.robots) setResponseHeader('X-Robots-Tag', 'noindex');

setResponseStatus(makeNumber(data.statusCode));
setResponseBody(data.statusMessage);

returnResponse();


